#include<bits/stdc++.h>
using namespace std;
struct ticket
{
    int price,time;
    bool flag;
} fre[100005];
int num=1,num2=0,n,cost;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        int a,b,c;
        cin>>a>>b>>c;
        if(a==0)
        {
            cost+=b;
            fre[++num2].time=c+45;
            fre[num2].price=b;
            fre[num2].flag=true;
        }
        else
        {
            while(num<=num2&&fre[num].time<c) num++;
            bool flag=true;
            for(int j=num;j<=num2;j++)
            {
                if(fre[j].flag&&fre[j].price>=b)
                {
                    flag=false;
                    fre[j].flag=false;
                    break;
                }
            }
            if(flag) cost+=b;
        }
    }
    cout<<cost;
    return 0;
}
